+    [Parameter] public ShippingInfo Shipping { get; set; } = default!;
+    [Parameter] public EventCallback OnNext { get; set; }
+
+    private CancellationTokenSource? _cts;
+    private bool _isValidating;
+    private string? _errorMessage;
+
+    private async Task ValidateAndProceed()
+    {
+        // Cancel any in-flight validation (user changed fields and re-clicked).
+        _cts?.Cancel();
+        _cts?.Dispose();
+        _cts = new CancellationTokenSource();
+        var token = _cts.Token;
+
+        _isValidating = true;
+        _errorMessage = null;
+
+        try
+        {
+            var isValid = await AddressValidator.ValidateAddressAsync(
+                Shipping.Address, Shipping.City, Shipping.ZipCode, token);
+
+            token.ThrowIfCancellationRequested();
+
+            if (isValid)
+            {
+                await OnNext.InvokeAsync();
+            }
+            else
+            {
+                _errorMessage = "The address could not be verified. Please check your details.";
+            }
+        }
+        catch (OperationCanceledException)
+        {
+            // Validation was cancelled — nothing to do.
+        }
+        finally
+        {
+            _isValidating = false;
+        }
+    }
+
+    public void Dispose()
+    {
+        _cts?.Cancel();
+        _cts?.Dispose();
+    }
+}
+
+<h3>Shipping Information</h3>
+
+<div class="form-group">
+    <label for="name">Name</label>
+    <input id="name" @bind="Shipping.Name" />
+</div>
+
+<div class="form-group">
+    <label for="address">Address</label>
+    <input id="address" @bind="Shipping.Address" />
+</div>
+
+<div class="form-group">
+    <label for="city">City</label>
+    <input id="city" @bind="Shipping.City" />
+</div>
+
+<div class="form-group">
+    <label for="zip">Zip Code</label>
+    <input id="zip" @bind="Shipping.ZipCode" />
+</div>
+
+@if (!string.IsNullOrEmpty(_errorMessage))
+{
+    <div class="validation-error">@_errorMessage</div>
+}
+
+<button disabled="@_isValidating" @onclick="ValidateAndProceed">
+    @if (_isValidating)
+    {
+        <span class="spinner"></span> @(" Validating…")
+    }
+    else
+    {
+        @("Next")
+    }
+</button>
+
